/**
 * Specialist: Hardcoded Secrets Detection
 * Scans source files for high-confidence hardcoded secrets using specific,
 * low-false-positive patterns (AWS keys, GitHub tokens, Google API keys,
 * Stripe live keys, Slack tokens, npm tokens, private keys, Slack webhooks).
 */

export const checkId = 'secrets';
export const name = 'No Hardcoded Secrets';
export const appliesTo = ['all'];

// ── Patterns ───────────────────────────────────────────────────────────

const SECRET_PATTERNS = [
  { regex: /-----BEGIN (?:RSA |EC |DSA |OPENSSH )?PRIVATE KEY-----/, name: 'private key' },
  { regex: /\b(AKIA[0-9A-Z]{16})\b/, name: 'AWS access key ID' },
  { regex: /\b(ghp_[a-zA-Z0-9]{36})\b/, name: 'GitHub personal access token' },
  { regex: /\b(gho_[a-zA-Z0-9]{36})\b/, name: 'GitHub OAuth token' },
  { regex: /\b(ghs_[a-zA-Z0-9]{36})\b/, name: 'GitHub server-to-server token' },
  { regex: /\b(ghu_[a-zA-Z0-9]{36})\b/, name: 'GitHub user-to-server token' },
  { regex: /\b(ghr_[a-zA-Z0-9]{36})\b/, name: 'GitHub refresh token' },
  { regex: /\b(AIza[0-9A-Za-z_-]{35})\b/, name: 'Google API key' },
  { regex: /\b((?:sk|rk|pk)_live_[a-zA-Z0-9]{24,})\b/, name: 'Stripe live key' },
  { regex: /\b(xox[baprs]-[a-zA-Z0-9-]+)\b/, name: 'Slack token' },
  { regex: /\b(npm_[a-zA-Z0-9]{36})\b/, name: 'npm token' },
  { regex: /(https:\/\/hooks\.slack\.com\/services\/T[a-zA-Z0-9_]+\/B[a-zA-Z0-9_]+\/[a-zA-Z0-9_]+)/, name: 'Slack webhook URL' },
];

const SAFE_PATTERNS = [
  /localhost/i,
  /127\.0\.0\.1/,
  /example\.com/i,
  /\btest_/i,
  /\bexample_/i,
  /dummy/i,
  /placeholder/i,
  /changeme/i,
  /YOUR_/i,
  /XXXX/i,
  /REDACTED/i,
  /process\.env\./,
  /import\.meta\.env\./,
  /Deno\.env/,
  /Bun\.env/,
];

const SKIP_PATHS = [
  /test/i, /spec/i, /__tests__/, /examples?/, /fixtures/, /docs?/,
  /\.test\./, /\.spec\./, /\.d\.ts$/, /\.lock$/, /\.env\./, /\.env$/, /\.min\.js$/,
  /mock/i, /snapshot/,
];

const VENDOR_PATHS = [
  /(?:^|\/)node_modules\//,
  /(?:^|\/)\.yarn\//,
  /(?:^|\/)\.pnpm\//,
  /(?:^|\/)vendor\//,
  /(?:^|\/)third_party\//,
  /(?:^|\/)dist\//,
  /(?:^|\/)build\//,
  /(?:^|\/)\.next\//,
  /(?:^|\/)\.nuxt\//,
  /(?:^|\/)\.output\//,
  /(?:^|\/)\.vercel\//,
  /(?:^|\/)\.netlify\//,
  /(?:^|\/)\.turbo\//,
  /(?:^|\/)\.cache\//,
  /(?:^|\/)\.parcel-cache\//,
  /(?:^|\/)coverage\//,
  /(?:^|\/)_next\//,
  /(?:^|\/)\.webpack\//,
];

const SCANNABLE_EXTS = /\.(js|ts|jsx|tsx|mjs|cjs|py|rb|go|java|kt|rs)$/;

// ── Helpers ────────────────────────────────────────────────────────────

function shouldScanFile(path) {
  if (!SCANNABLE_EXTS.test(path)) return false;
  if (SKIP_PATHS.some((p) => p.test(path))) return false;
  if (VENDOR_PATHS.some((p) => p.test(path))) return false;
  return true;
}

function isSafeLine(line) {
  return SAFE_PATTERNS.some((p) => p.test(line));
}

function isCommentLine(line) {
  const trimmed = line.trim();
  return (
    trimmed.startsWith('//') ||
    trimmed.startsWith('*') ||
    trimmed.startsWith('#')
  );
}

// ── Main Check ─────────────────────────────────────────────────────────

export async function check(context) {
  const { tree, files } = context;

  try {
    const sourceFiles = tree.filter(shouldScanFile).slice(0, 30);
    if (sourceFiles.length === 0) {
      const isEmptyRepo = tree.length === 0;
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: isEmptyRepo ? 'Repo is empty — nothing to scan' : `No scannable source files in ${tree.length} file(s)`,
        findings: [],
      };
    }

    const findings = [];

    for (const filePath of sourceFiles) {
      const content = await files.get(filePath);
      if (!content) continue;

      const text = typeof content === 'string' ? content : content.toString('utf-8');
      const lines = text.split('\n');

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i];

        if (isSafeLine(line)) continue;
        if (isCommentLine(line)) continue;

        for (const pattern of SECRET_PATTERNS) {
          if (pattern.regex.test(line)) {
            findings.push({
              file: filePath,
              line: i + 1,
              issue: `Potential hardcoded ${pattern.name}`,
            });
            break;
          }
        }
      }
    }

    if (findings.length === 0) {
      return {
        checkId,
        status: 'pass',
        confidence: 'medium',
        message: `No secrets detected in ${sourceFiles.length} scanned file(s)`,
        findings: [],
      };
    }

    return {
      checkId,
      status: 'fail',
      confidence: 'high',
      message: `${findings.length} potential secret(s) found in ${sourceFiles.length} scanned file(s)`,
      findings,
    };
  } catch (err) {
    return {
      checkId,
      status: 'check-it',
      confidence: 'low',
      message: `Error during scan: ${err.message}`,
      findings: [],
    };
  }
}
